onClick:
{{
  (() => {
    // 1. Manutenção de sessão
    JSutils.resetInactivityTimer();

    // 2. Extração de valores (Helper para evitar repetição de .trim())
    const getVal = (widget, isDate = false) => {
      const val = widget?.text || widget?.selectedDate || widget?.selectedOptionValue || "";
      return typeof val === "string" ? val.trim() : val;
    };

    // 3. Montagem do objeto conforme o banco de dados
    const formData = {
      ani002_imagem:          ImagePet.image || "",
      ani002_tutor:           appsmith.store.modalContexto?.tutorID || null,
      ani002_nome:            getVal(Input1Nome),
      ani002_datanasc:        DatePicker1Nascimento.selectedDate || null,
      ani002_idade:           getVal(Input2Idade),
      ani002_peso:            getVal(Input3Peso),
      ani002_registro:        getVal(Input3Registro),
      ani002_microchip:       getVal(Input3Microchip),
      ani002_data_obito:      DatePicker1Obito.selectedDate || null,
      ani002_tipo:            Select1Especie.selectedOptionValue,
      ani002_raca:            Select1Raca.selectedOptionValue,
      ani002_sexo:            Select1Sexo.selectedOptionValue,
      ani002_castrado:        Select1Castrado.selectedOptionValue,
      ani002_porte:           Select1Porte.selectedOptionValue,
      ani002_pelagem:         Select1Pelagem.selectedOptionValue,
      ani002_cor:             Select1Cor.selectedOptionValue,
      ani002_temp:            Select1Temperamento.selectedOptionValue,
      ani002_convivio:        Select1Convivio.selectedOptionValue,
      ani002_vet:             Select1Veterinario.selectedOptionValue,
      ani002_clinica:         Select1Clinica.selectedOptionValue,
      ani002_canil:           getVal(Input1Canil),
      ani002_registro_pedigree: getVal(Input1Pedigree),
      ani002_nome_registro:   getVal(Input1PedigreeNome),
      ani002_observacao:      getVal(Input1Observacao)  
    };

    const isInsert = appsmith.store.modalContexto?.acaoTipo === "ADICIONAR";

    // 4. Disparo do Modal com os dados preparados
    return JSconfirmationPET.showModal({
      entidade: "PET",
			action: isInsert ? "Insert" : "Update",
      message: isInsert ? "Deseja salvar este novo registro?" : "Deseja salvar as alterações deste registro?",
      icon: isInsert ? "plus" : "edit",
      color: isInsert ? "green" : "orange",
      row: {
        ...formData,
        // Se for Update, garante que o ID venha da nossa referência estável no Store
        ani002_id: isInsert ? undefined : appsmith.store.petSelecionado?.ani002_id
      }
    });
  })()
}}
